import { HydrateClient } from "@repo/app-trpc/server";
import {
  SidebarInset,
  SidebarProvider,
  SidebarTrigger,
} from "@repo/ui/components/ui/sidebar";
import { Loader2 } from "lucide-react";
import { redirect } from "next/navigation";
import { Suspense } from "react";
import { AppHeader } from "~/components/app-header";
import { AppSidebar } from "~/components/app-sidebar";
import { CommandPalette } from "~/components/command-palette";
import { WorkspaceHeader } from "~/components/workspace-header";
import { getGitHubBinding } from "~/lib/github-binding";
import { requireOrgAccess } from "~/lib/org-access-clerk";

interface WorkspaceLayoutProps {
  children: React.ReactNode;
  params: Promise<{ slug: string }>;
}

/**
 * Workspace layout — requires active GitHub binding.
 * Redirects to /[slug]/onboard if binding is missing.
 *
 * Structure:
 * - Header row: TeamSwitcher (sidebar-aligned, desktop) | SidebarTrigger (mobile) + AppHeader
 * - Content row: AppSidebar | SidebarInset
 */
export default async function WorkspaceLayout({
  children,
  params,
}: WorkspaceLayoutProps) {
  const { slug } = await params;
  const { org } = await requireOrgAccess(slug); // cache()'d — deduped with parent layout

  // Check GitHub binding — redirect to onboard if missing
  const binding = await getGitHubBinding(org.id);
  if (!binding || binding.status !== "active") {
    redirect(`/${slug}/onboard`);
  }

  return (
    <HydrateClient>
      <SidebarProvider className="!h-full !min-h-0 flex-col overflow-hidden bg-sidebar">
        {/* Header row — full width, two columns */}
        <div className="flex h-14 w-full shrink-0 items-center">
          {/* Left: matches sidebar width, desktop only */}
          <div className="hidden w-[--sidebar-width] shrink-0 items-center justify-between px-4 lg:flex">
            <Suspense fallback={<div className="h-6 w-24" />}>
              <WorkspaceHeader />
            </Suspense>
          </div>
          {/* Right: remaining space */}
          <div className="flex flex-1 items-center px-4">
            <SidebarTrigger className="lg:hidden" />
            <Suspense fallback={<div className="h-8 w-8" />}>
              <AppHeader />
            </Suspense>
          </div>
        </div>

        {/* Sidebar + Content row */}
        <div className="flex min-h-0 flex-1 overflow-hidden">
          <AppSidebar />
          <CommandPalette />
          {/* pr-2 pb-2 creates the gap for the inset card */}
          <div className="flex min-h-0 flex-1 flex-col overflow-hidden lg:pr-2 lg:pb-2">
            <SidebarInset className="overflow-hidden lg:rounded-xl lg:shadow-sm">
              <Suspense fallback={<PageLoadingSkeleton />}>{children}</Suspense>
            </SidebarInset>
          </div>
        </div>
      </SidebarProvider>
    </HydrateClient>
  );
}

function PageLoadingSkeleton() {
  return (
    <div className="flex h-full min-h-0 w-full items-center justify-center">
      <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
    </div>
  );
}

