31	
32	// ── GitHub-Specific Capabilities ──
33	
34	export async function createGitHubAppJWT(config: GitHubConfig): Promise<string> {
35	  const now = Math.floor(Date.now() / 1000);
36	  return createRS256JWT(
37	    { iss: config.appId, iat: now - 60, exp: now + 600 },
38	    config.privateKey
39	  );
40	}
41	
42	async function getInstallationToken(
43	  config: GitHubConfig,
44	  installationId: string
45	): Promise<string> {
46	  if (!/^\d+$/.test(installationId)) {
47	    throw new Error("Invalid GitHub installation ID: must be numeric");
48	  }
49	
50	  const jwt = await createGitHubAppJWT(config);
51	  const response = await fetch(
52	    `https://api.github.com/app/installations/${installationId}/access_tokens`,
53	    {
54	      method: "POST",
55	      signal: AbortSignal.timeout(10_000),
56	      headers: {
57	        Authorization: `Bearer ${jwt}`,
58	        Accept: "application/vnd.github+json",
59	        "User-Agent": "lightfast-platform",
60	        "X-GitHub-Api-Version": "2022-11-28",
61	      },
62	    }
63	  );
64	  if (!response.ok) {
65	    const body = await readErrorBody(response);
66	    throw new Error(
67	      `GitHub installation token request failed: ${response.status} ${body}`
68	    );
69	  }
70	
71	  const data = (await response.json()) as Record<string, unknown>;
72	  if (typeof data.token !== "string" || data.token.length === 0) {
73	    throw new Error("GitHub installation token response missing valid token");
74	  }
75	  return data.token;
76	}
77	
78	// ── Provider Definition ──
79	
80	export const github = defineWebhookProvider({
81	  ...PROVIDER_DISPLAY.github,
82	  configSchema: githubConfigSchema,
83	  accountInfoSchema: githubAccountInfoSchema,
84	  providerConfigSchema: githubProviderConfigSchema,
85	
86	  categories: {
87	    pull_request: {
88	      label: "Pull Requests",
89	      description: "Capture PR opens, merges, closes, and reopens",
90	      type: "observation",
91	    },
92	    issues: {
93	      label: "Issues",
94	      description: "Capture issue opens, closes, and reopens",
95	      type: "observation",
96	    },
97	    issue_comment: {
98	      label: "Comments",
99	      description: "Capture comments on issues and pull requests",
100	      type: "observation",
101	    },
102	  },
103	
104	  events: {
105	    pull_request: actionEvent({
106	      label: "Pull Requests",
107	      weight: 50,
108	      schema: preTransformGitHubPullRequestEventSchema,
109	      transform: transformGitHubPullRequest,
110	      actions: {
111	        opened: { label: "PR Opened", weight: 50 },
112	        closed: { label: "PR Closed", weight: 45 },
113	        merged: { label: "PR Merged", weight: 60 },
114	        reopened: { label: "PR Reopened", weight: 40 },
115	        "ready-for-review": { label: "Ready for Review", weight: 45 },
116	      },
117	    }),
118	    issues: actionEvent({
119	      label: "Issues",
120	      weight: 45,
121	      schema: preTransformGitHubIssuesEventSchema,
122	      transform: transformGitHubIssue,
123	      actions: {
124	        opened: { label: "Issue Opened", weight: 45 },
125	        closed: { label: "Issue Closed", weight: 40 },
126	        reopened: { label: "Issue Reopened", weight: 40 },
127	      },
128	    }),
129	    issue_comment: actionEvent({
130	      label: "Comments",
131	      weight: 25,
132	      schema: preTransformGitHubIssueCommentEventSchema,
133	      transform: transformGitHubIssueComment,
134	      actions: {
135	        created: { label: "Comment Added", weight: 25 },
136	        edited: { label: "Comment Edited", weight: 20 },
137	        deleted: { label: "Comment Deleted", weight: 20 },
138	      },
139	    }),
140	  },
141	
142	  webhook: {
143	    headersSchema: z.object({
144	      "x-hub-signature-256": z.string(),
145	      "x-github-event": z.string(),
146	      "x-github-delivery": z.string(),
147	    }),
148	    extractSecret: (config) => config.webhookSecret,
149	    signatureScheme: hmac({
150	      algorithm: "sha256",
151	      signatureHeader: "x-hub-signature-256",
152	      prefix: "sha256=",
153	    }),
154	    extractEventType: (headers) => headers.get("x-github-event") ?? "unknown",
155	    extractDeliveryId: (headers) =>
156	      headers.get("x-github-delivery") ?? crypto.randomUUID(),
157	    extractResourceId: (payload) => {
158	      const p = payload as {
159	        repository?: { id: number | string };
160	        installation?: { id: number | string };
161	      };
162	      if (p.repository?.id != null) {
163	        return String(p.repository.id);
164	      }
165	      if (p.installation?.id != null) {
166	        return String(p.installation.id);
167	      }
168	      return null;
169	    },
170	    parsePayload: (raw) => githubWebhookPayloadSchema.parse(raw),
171	  },
172	
173	  auth: {
174	    kind: "app-token" as const,
175	    buildInstallUrl: (config, state) => {
176	      const url = new URL(
177	        `https://github.com/apps/${config.appSlug}/installations/new`
178	      );
179	      url.searchParams.set("state", state);
180	      return url.toString();
181	    },
182	    usesStoredToken: false as const,
183	    getActiveToken: async (config, storedExternalId, _storedAccessToken) => {
184	      return getInstallationToken(config, storedExternalId);
185	    },
186	    getAppToken: async (config) => createGitHubAppJWT(config),
187	    revokeAccess: async (config, _externalId) => {
188	      // GitHub App installations are revoked via the GitHub UI or GitHub API.
189	      // Installation tokens expire automatically; no explicit revocation call needed.
190	      // The app can be uninstalled via DELETE /app/installations/:installation_id.
191	      const jwt = await createGitHubAppJWT(config);
192	      const response = await fetch(
193	        `https://api.github.com/app/installations/${_externalId}`,
194	        {
195	          method: "DELETE",
196	          signal: AbortSignal.timeout(15_000),
197	          headers: {
198	            Authorization: `Bearer ${jwt}`,
199	            Accept: "application/vnd.github+json",
200	            "User-Agent": "lightfast-platform",
201	            "X-GitHub-Api-Version": "2022-11-28",
202	          },
203	        }
204	      );
205	      // 204 = success, 404 = already uninstalled — both are fine
206	      if (!response.ok && response.status !== 404) {
207	        const body = await readErrorBody(response);
208	        throw new Error(
209	          `GitHub installation revocation failed: ${response.status} ${body}`
210	        );
211	      }
212	    },
213	    processCallback: (_config, query) => {
214	      const installationId = query.installation_id;
215	      const setupAction = query.setup_action;
216	
217	      if (setupAction === "request") {
218	        return Promise.reject(
219	          new Error("setup_action=request is not yet implemented")
220	        );
221	      }
222	      if (setupAction === "update") {
223	        return Promise.reject(
224	          new Error("setup_action=update is not yet implemented")
225	        );
226	      }
227	      if (!installationId) {
228	        return Promise.reject(new Error("missing installation_id"));
229	      }
230	
231	      const now = new Date().toISOString();
232	      return Promise.resolve({
233	        status: "connected-no-token",
234	        externalId: installationId,
235	        accountInfo: {
236	          version: 1 as const,
237	          sourceType: "github" as const,
238	          events: ["pull_request", "issues", "issue_comment"],
239	          installedAt: now,
240	          lastValidatedAt: now,
241	          raw: {},
242	        },
243	      } satisfies CallbackResult<GitHubAccountInfo>);
244	    },
245	  },
246	
247	  defaultSyncEvents: ["pull_request", "issues", "issue_comment"],
248	
249	  buildProviderConfig: ({ defaultSyncEvents }) => ({
250	    provider: "github" as const,
251	    type: "repository" as const,
252	    sync: {
253	      events: [...defaultSyncEvents],
254	      autoSync: true,
255	    },
