  "name": "@db/app",
  "version": "0.1.0",
  "private": true,
  "type": "module",
  "sideEffects": false,
  "exports": {
    ".": {
      "types": "./src/index.ts",
      "default": "./src/index.ts"
    },
    "./schema": {
      "types": "./src/schema/index.ts",
      "default": "./src/schema/index.ts"
    },
    "./client": {
      "types": "./src/client.ts",
      "default": "./src/client.ts"
    },
    "./utils": {
      "types": "./src/utils/org.ts",
      "default": "./src/utils/org.ts"
    },
    "./env": {
      "types": "./src/env.ts",
      "default": "./src/env.ts"
    },
    "./migrations": "./src/migrations/meta/_journal.json"
  },
  "license": "FSL-1.1-Apache-2.0",
  "scripts": {
