}

const del = await sql`DELETE FROM drizzle.__drizzle_migrations WHERE id = 337`;
console.log("DELETE rows affected:", del.length ?? 0);

const after = await sql`SELECT to_regclass('"lightfast_github_org_bindings"') AS t, (SELECT count(*)::int FROM drizzle.__drizzle_migrations WHERE id = 337) AS rows`;
